import React, { useState, useEffect } from 'react';

// ---------- STORAGE (versão para hospedagem real, usa localStorage do navegador) ----------
// Observação: como o site está fora do ambiente Claude, os dados ficam salvos no navegador
// de cada pessoa que acessa. Para uma escala/calendário compartilhado entre todos os
// membros da igreja, o ideal no futuro é conectar a um banco de dados (posso ajudar nisso depois).
if (typeof window !== 'undefined' && !window.storage) {
  window.storage = {
    async get(key) {
      try {
        const raw = localStorage.getItem('majs_' + key);
        if (raw === null) return null;
        return { key, value: raw };
      } catch (e) {
        return null;
      }
    },
    async set(key, value) {
      try {
        localStorage.setItem('majs_' + key, value);
        return { key, value };
      } catch (e) {
        return null;
      }
    },
    async delete(key) {
      try {
        localStorage.removeItem('majs_' + key);
        return { key, deleted: true };
      } catch (e) {
        return null;
      }
    },
  };
}

