// ---------- REVEAL ON SCROLL ----------

function Reveal({ children, delay = 0, as = 'div', style = {}, className = '' }) {
  const ref = React.useRef(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            setVisible(true);
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.15, rootMargin: '0px 0px -8% 0px' }
    );
    observer.observe(el);
    return () => observer.disconnect();
  }, []);

  const Tag = as;
  return (
    <Tag
      ref={ref}
      className={`reveal ${visible ? 'is-visible' : ''} ${className}`}
      style={{ transitionDelay: visible ? `${delay}s` : '0s', ...style }}
    >
      {children}
    </Tag>
  );
}

// ---------- COMPONENTE PRINCIPAL ----------

export default function MAJSSite() {
  const [page, setPage] = useState('home');
  const [activeDept, setActiveDept] = useState(null);
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [escala, setEscala] = useState(ESCALA_INICIAL);
  const [eventos, setEventos] = useState(EVENTOS_INICIAIS);
  const [louvores, setLouvores] = useState(LOUVORES_INICIAIS);
  const [ministerios, setMinisterios] = useState(MINISTERIOS_INICIAIS);
  const [editMode, setEditMode] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 40);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  // Carrega dados persistidos
  useEffect(() => {
    (async () => {
      try {
        const e = await window.storage?.get('escala', true);
        if (e?.value) setEscala(JSON.parse(e.value));
      } catch (err) {}
      try {
        const ev = await window.storage?.get('eventos', true);
        if (ev?.value) setEventos(JSON.parse(ev.value));
      } catch (err) {}
      try {
        const lv = await window.storage?.get('louvores', true);
        if (lv?.value) setLouvores(JSON.parse(lv.value));
      } catch (err) {}
      try {
        const mn = await window.storage?.get('ministerios', true);
        if (mn?.value) setMinisterios(JSON.parse(mn.value));
      } catch (err) {}
    })();
  }, []);

  const goTo = (p, dept = null) => {
    setPage(p);
    setActiveDept(dept);
    setMenuOpen(false);
    window.scrollTo({ top: 0, behavior: 'instant' });
  };

  return (
    <div style={{ fontFamily: "'Inter', system-ui, sans-serif", background: '#FAF8F4', color: '#1A1410', minHeight: '100vh' }}>
      <GlobalStyles />
      <Nav scrolled={scrolled} goTo={goTo} page={page} menuOpen={menuOpen} setMenuOpen={setMenuOpen} />

      {page === 'home' && <HomePage goTo={goTo} eventos={eventos} escala={escala} louvores={louvores} />}
      {page === 'departamento' && <DepartamentoPage dept={DEPARTAMENTOS.find(d => d.id === activeDept)} goTo={goTo} />}
      {page === 'calendario' && <CalendarioPage eventos={eventos} setEventos={setEventos} editMode={editMode} setEditMode={setEditMode} goTo={goTo} />}
      {page === 'escala' && <EscalaPage escala={escala} setEscala={setEscala} editMode={editMode} setEditMode={setEditMode} goTo={goTo} />}
      {page === 'louvores' && <LouvoresPage louvores={louvores} setLouvores={setLouvores} editMode={editMode} setEditMode={setEditMode} goTo={goTo} />}
      {page === 'ministerios' && <MinisteriosPage ministerios={ministerios} setMinisterios={setMinisterios} editMode={editMode} setEditMode={setEditMode} goTo={goTo} />}
      {page === 'pastores' && <PastoresPage goTo={goTo} />}
      {page === 'familia' && <FamiliaPage goTo={goTo} />}

      <Footer goTo={goTo} />
    </div>
  );
}

