// ---------- CALENDÁRIO (editável) ----------

function CalendarioPage({ eventos, setEventos, editMode, setEditMode, goTo }) {
  const [novoEvento, setNovoEvento] = useState({ data: '', titulo: '', tipo: 'evento' });
  const [saving, setSaving] = useState(false);

  const salvar = async (lista) => {
    setSaving(true);
    try {
      await window.storage?.set('eventos', JSON.stringify(lista), true);
    } catch (e) {}
    setSaving(false);
  };

  const adicionar = () => {
    if (!novoEvento.data || !novoEvento.titulo) return;
    const lista = [...eventos, novoEvento].sort((a, b) => new Date(a.data) - new Date(b.data));
    setEventos(lista);
    salvar(lista);
    setNovoEvento({ data: '', titulo: '', tipo: 'evento' });
  };

  const remover = (idx) => {
    const lista = eventos.filter((_, i) => i !== idx);
    setEventos(lista);
    salvar(lista);
  };

  return (
    <PageShell titulo="Calendário de Eventos" subtitulo="Tudo que acontece na MAJS ao longo do ano" goTo={goTo}>
      <EditToggle editMode={editMode} setEditMode={setEditMode} saving={saving} />

      {editMode && (
        <div style={{
          background: '#FFFFFF', border: '1px solid #ECE4D4', borderRadius: 14, padding: 20, marginBottom: 28,
          display: 'grid', gridTemplateColumns: '1fr 2fr auto', gap: 10, alignItems: 'end',
        }}>
          <Field label="Data">
            <input type="date" value={novoEvento.data} onChange={e => setNovoEvento({ ...novoEvento, data: e.target.value })} style={inputStyle} />
          </Field>
          <Field label="Evento">
            <input type="text" placeholder="Nome do evento" value={novoEvento.titulo} onChange={e => setNovoEvento({ ...novoEvento, titulo: e.target.value })} style={inputStyle} />
          </Field>
          <button onClick={adicionar} style={btnPrimary}>Adicionar</button>
        </div>
      )}

      <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
        {eventos.length === 0 && <EmptyState texto="Nenhum evento cadastrado ainda." />}
        {eventos.map((ev, i) => (
          <Reveal key={i} delay={Math.min(i, 6) * 0.06}>
            <div style={{
              display: 'flex', alignItems: 'center', justifyContent: 'space-between', gap: 16,
              background: '#FFFFFF', border: '1px solid #ECE4D4', borderRadius: 12, padding: '16px 20px',
            }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
                <div style={{
                  width: 54, textAlign: 'center', background: '#1A1410', color: '#FAF8F4', borderRadius: 10, padding: '8px 4px',
                }}>
                  <p className="font-mono" style={{ fontSize: 10, color: '#D4A23C' }}>{mesAbreviado(ev.data)}</p>
                  <p className="font-display" style={{ fontSize: 18, fontWeight: 700 }}>{diaDoMes(ev.data)}</p>
                </div>
                <div>
                  <p style={{ fontWeight: 700, fontSize: 15 }}>{ev.titulo}</p>
                  <p style={{ fontSize: 13, color: '#8A8071' }}>{formatarData(ev.data)}</p>
                </div>
              </div>
              {editMode && (
                <button onClick={() => remover(i)} style={btnGhostDanger}>Remover</button>
              )}
            </div>
          </Reveal>
        ))}
      </div>
    </PageShell>
  );
}

// ---------- ESCALA (editável) ----------

function EscalaPage({ escala, setEscala, editMode, setEditMode, goTo }) {
  const [saving, setSaving] = useState(false);
  const [novo, setNovo] = useState({ tipo: 'liturgia', dia: 'Domingo', pessoa: '' });

  const salvar = async (nova) => {
    setSaving(true);
    try { await window.storage?.set('escala', JSON.stringify(nova), true); } catch (e) {}
    setSaving(false);
  };

  const adicionar = () => {
    if (!novo.pessoa) return;
    const nova = { ...escala, [novo.tipo]: [...escala[novo.tipo], { dia: novo.dia, pessoa: novo.pessoa }] };
    setEscala(nova);
    salvar(nova);
    setNovo({ ...novo, pessoa: '' });
  };

  const remover = (tipo, idx) => {
    const nova = { ...escala, [tipo]: escala[tipo].filter((_, i) => i !== idx) };
    setEscala(nova);
    salvar(nova);
  };

  return (
    <PageShell titulo="Escala da Semana" subtitulo="Liturgia e limpeza — quem serve essa semana" goTo={goTo}>
      <EditToggle editMode={editMode} setEditMode={setEditMode} saving={saving} />

      {editMode && (
        <div style={{
          background: '#FFFFFF', border: '1px solid #ECE4D4', borderRadius: 14, padding: 20, marginBottom: 28,
          display: 'grid', gridTemplateColumns: '1fr 1fr 1.5fr auto', gap: 10, alignItems: 'end',
        }}>
          <Field label="Tipo">
            <select value={novo.tipo} onChange={e => setNovo({ ...novo, tipo: e.target.value })} style={inputStyle}>
              <option value="liturgia">Liturgia</option>
              <option value="limpeza">Limpeza</option>
            </select>
          </Field>
          <Field label="Dia">
            <select value={novo.dia} onChange={e => setNovo({ ...novo, dia: e.target.value })} style={inputStyle}>
              {DIAS_SEMANA.map(d => <option key={d} value={d}>{d}</option>)}
            </select>
          </Field>
          <Field label="Responsável">
            <input type="text" placeholder="Nome" value={novo.pessoa} onChange={e => setNovo({ ...novo, pessoa: e.target.value })} style={inputStyle} />
          </Field>
          <button onClick={adicionar} style={btnPrimary}>Adicionar</button>
        </div>
      )}

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: 24 }}>
        <EscalaBloco titulo="Liturgia" itens={escala.liturgia} tipo="liturgia" editMode={editMode} remover={remover} cor="#E8631C" />
        <EscalaBloco titulo="Limpeza" itens={escala.limpeza} tipo="limpeza" editMode={editMode} remover={remover} cor="#D4A23C" />
      </div>
    </PageShell>
  );
}

function EscalaBloco({ titulo, itens, tipo, editMode, remover, cor }) {
  return (
    <div>
      <h3 className="font-display" style={{ fontSize: 20, fontWeight: 600, marginBottom: 14, color: cor }}>{titulo}</h3>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
        {itens.length === 0 && <EmptyState texto="Ninguém escalado ainda." />}
        {itens.map((it, i) => (
          <div key={i} style={{
            display: 'flex', justifyContent: 'space-between', alignItems: 'center',
            background: '#FFFFFF', border: '1px solid #ECE4D4', borderRadius: 10, padding: '12px 16px',
          }}>
            <div>
              <span className="font-mono" style={{ fontSize: 11, color: '#8A8071', textTransform: 'uppercase' }}>{it.dia}</span>
              <p style={{ fontWeight: 600, fontSize: 15 }}>{it.pessoa}</p>
            </div>
            {editMode && <button onClick={() => remover(tipo, i)} style={btnGhostDanger}>Remover</button>}
          </div>
        ))}
      </div>
    </div>
  );
}

// ---------- LOUVORES (editável) ----------

function LouvoresPage({ louvores, setLouvores, editMode, setEditMode, goTo }) {
  const [saving, setSaving] = useState(false);
  const [novo, setNovo] = useState({ semana: '', musica: '', ministro: '' });

  const salvar = async (lista) => {
    setSaving(true);
    try { await window.storage?.set('louvores', JSON.stringify(lista), true); } catch (e) {}
    setSaving(false);
  };

  const adicionar = () => {
    if (!novo.musica) return;
    const lista = [novo, ...louvores];
    setLouvores(lista);
    salvar(lista);
    setNovo({ semana: '', musica: '', ministro: '' });
  };

  const remover = (idx) => {
    const lista = louvores.filter((_, i) => i !== idx);
    setLouvores(lista);
    salvar(lista);
  };

  return (
    <PageShell titulo="Louvores da Semana" subtitulo="O que o ministério de louvor ministrou" goTo={goTo}>
      <EditToggle editMode={editMode} setEditMode={setEditMode} saving={saving} />

      {editMode && (
        <div style={{
          background: '#FFFFFF', border: '1px solid #ECE4D4', borderRadius: 14, padding: 20, marginBottom: 28,
          display: 'grid', gridTemplateColumns: '1fr 1.5fr 1fr auto', gap: 10, alignItems: 'end',
        }}>
          <Field label="Semana">
            <input type="text" placeholder="Ex: 14 a 20 jun" value={novo.semana} onChange={e => setNovo({ ...novo, semana: e.target.value })} style={inputStyle} />
          </Field>
          <Field label="Música">
            <input type="text" placeholder="Nome da música" value={novo.musica} onChange={e => setNovo({ ...novo, musica: e.target.value })} style={inputStyle} />
          </Field>
          <Field label="Ministrado por">
            <input type="text" placeholder="Nome" value={novo.ministro} onChange={e => setNovo({ ...novo, ministro: e.target.value })} style={inputStyle} />
          </Field>
          <button onClick={adicionar} style={btnPrimary}>Adicionar</button>
        </div>
      )}

      <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
        {louvores.length === 0 && <EmptyState texto="Nenhum louvor registrado ainda." />}
        {louvores.map((l, i) => (
          <div key={i} style={{
            display: 'flex', justifyContent: 'space-between', alignItems: 'center',
            background: '#FFFFFF', border: '1px solid #ECE4D4', borderLeft: '3px solid #D98A2B',
            borderRadius: 10, padding: '16px 20px',
          }}>
            <div>
              {l.semana && <p className="font-mono" style={{ fontSize: 11, color: '#8A8071', textTransform: 'uppercase' }}>{l.semana}</p>}
              <p className="font-display" style={{ fontWeight: 600, fontSize: 17 }}>{l.musica}</p>
              {l.ministro && <p style={{ fontSize: 13, color: '#8A8071', marginTop: 2 }}>{l.ministro}</p>}
            </div>
            {editMode && <button onClick={() => remover(i)} style={btnGhostDanger}>Remover</button>}
          </div>
        ))}
      </div>
    </PageShell>
  );
}

// ---------- MINISTÉRIOS (editável) ----------

function MinisteriosPage({ ministerios, setMinisterios, editMode, setEditMode, goTo }) {
  const [saving, setSaving] = useState(false);

  const salvar = async (lista) => {
    setSaving(true);
    try { await window.storage?.set('ministerios', JSON.stringify(lista), true); } catch (e) {}
    setSaving(false);
  };

  const atualizarLider = (idx, novoLider) => {
    const lista = ministerios.map((m, i) => i === idx ? { ...m, lider: novoLider } : m);
    setMinisterios(lista);
  };

  const salvarLider = (idx) => {
    salvar(ministerios);
  };

  const coresMinisterios = ['#E8631C', '#D4A23C', '#8FBF3F', '#2B4C7E', '#8B1E2E', '#3F6B3F', '#D98A2B', '#E0598F'];

  return (
    <PageShell titulo="Ministérios" subtitulo="Áreas de serviço da MAJS e suas lideranças" goTo={goTo}>
      <EditToggle editMode={editMode} setEditMode={setEditMode} saving={saving} />

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: 14 }}>
        {ministerios.map((m, i) => (
          <Reveal key={m.nome} delay={(i % 5) * 0.07}>
            <div style={{
              background: '#FFFFFF', border: '1px solid #ECE4D4', borderRadius: 12, padding: '18px 20px',
              borderLeft: `3px solid ${coresMinisterios[i % coresMinisterios.length]}`,
            }}>
              <p className="font-display" style={{ fontWeight: 600, fontSize: 17 }}>{m.nome}</p>
              {editMode ? (
                <input
                  type="text"
                  value={m.lider}
                  placeholder="Nome do líder"
                  onChange={e => atualizarLider(i, e.target.value)}
                  onBlur={() => salvarLider(i)}
                  style={{ ...inputStyle, marginTop: 8, fontSize: 14 }}
                />
              ) : (
                <p style={{ fontSize: 14, color: '#8A8071', marginTop: 6 }}>
                  {m.lider && m.lider !== 'A definir' ? `Líder: ${m.lider}` : 'Líder a definir'}
                </p>
              )}
            </div>
          </Reveal>
        ))}
      </div>
    </PageShell>
  );
}

